ame":"entryUID","type":"bytes32"}],"name":"targetAsMemberKey","outputs":[{"internalType":"bytes32","name":"","type":"bytes32"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"bytes32","name":"listUID","type":"bytes32"},{"internalType":"address","name":"lens","type":"address"},{"internalType":"bytes32","name":"entryUID","type":"bytes32"}],"name":"targetAsUID","outputs":[{"internalType":"bytes32","name":"","type":"bytes32"}],"stateMutability":"view","type":"function"}],"devdoc":{"details":"Stateless view contract over ListEntryResolver + EAS. Redeployable without      changing any schema UID (address not baked into any schema). ADR-0044 §5.      getMode() reads LIST attestation directly from EAS (schema-check BEFORE decode).      entries() reads EntryRecord[] from resolver storage — zero per-entry EAS calls.      Typed accessors are safe-by-construction: validate schema, lens, active, listUID, mode.","kind":"dev","methods":{},"title":"ListReader","version":1},"userdoc":{"kind":"user","methods":{"countOf(bytes32,address,bytes32)":{"notice":"O(1) membership check. Compare to 0 explicitly — no isMember bool (ADR-0044 §5). identityKey: bytes32(uint160(addr)) for ADDR, UID for SCHEMA, member key for ANY."},"entries(bytes32,address,uint256,uint256)":{"notice":"Page of active entries (insertion order). No per-entry eas.getAttestation() — all fields read inline from EntryRecord[]. Pagination is NOT snapshot-isolated."},"getMode(bytes32)":{"notice":"Decode LIST attestation directly from EAS. Schema-checked BEFORE data decode. Works for empty lists. Returns exists=false for non-LIST UIDs."},"length(bytes32,address)":{"notice":"Number of active entries for (list, attester). O(1)."}},"version":1}},"settings":{"compilationTarget":{"contracts/ListReader.sol":"ListReader"},"evmVersion":"paris","libraries":{},"metadata":{"bytecodeHash":"ipfs","useLiteralContent":true},"optimizer":{"enabled":true,"runs":200},"remappings":[],"viaIR":true},"sources":{"@ethereum-